import{_ as a,o,c as n,j as e,a as r}from"./chunks/framework.DH-ORP1j.js";const _=JSON.parse('{"title":"唐朝兴盛的原因：政治：国家统一，社会稳定","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-14.md","filePath":"notes/note-14.md"}'),s={name:"notes/note-14.md"};function c(d,t,l,i,p,m){return o(),n("div",null,[...t[0]||(t[0]=[e("h1",{id:"唐朝兴盛的原因-政治-国家统一-社会稳定",tabindex:"-1"},[r("唐朝兴盛的原因：政治：国家统一，社会稳定 "),e("a",{class:"header-anchor",href:"#唐朝兴盛的原因-政治-国家统一-社会稳定","aria-label":'Permalink to "唐朝兴盛的原因：政治：国家统一，社会稳定"'},"​")],-1),e("p",null,"唐朝兴盛的原因：政治：国家统一，社会稳定；统治者以民为本，实行有利于生产发展的措施；完善科举制度，重视人才培养；采取开明的民族政策，民族关系相对融洽；开放的对外政策，中外交流频繁；经济：生产力发展（曲辕犁、筒车），经济繁荣；文化：注重文教，文化繁荣。交通：海上陆上丝绸之路，交通发达。 宋朝兴盛的原因：政治：政府采取重文轻武政策，重视文教事业的发展；中外交流频繁；经济：生产力发展（秧马），经济繁荣；经济重心南移；文化：改革科举制，文化昌盛、人才辈出。交通：海上丝绸之路，交通发达。 1、闭关锁国原因：①清朝统治者认为天朝物产丰富，无所不有，不需与外交交流。②清朝统治者担心西方殖民者的侵犯和沿海居民同外国人交往，会危及自己的统治。 2、闭关锁国表现：①顺治颁布“禁海令”；②建台湾府后，开放宁波、漳州等地为通商口岸；③1757年，只留广州一处通商口岸，由广州十三行统一经营对外贸易并管理外商。 3、闭关锁国政策的影响：对西方殖民者的侵略活动，曾起到过一定的自卫作用，但也使中国逐渐落伍于世界历史的发展进程。 4、长篇章回体小说的开山之作：《三国演义》 5、浪漫主义色的神话小说：《西游记》 6、我国古代最优秀的长篇小说：《红楼梦》 7、戏剧代表：明朝汤显祖《牡丹亭》 8、清朝的文化专制：文字狱、康熙、雍正和乾隆。 1、唐朝书法家是？颜真卿、柳公权、欧阳询 2、明清单元目录：统一多民族国家的巩固和发展 3、以下哪些发明由阿拉伯人传播到欧洲？B指南针C火药 A活字印刷术（蒙古人西征） 4、清朝疆域四至：西跨葱岭，北接西伯利亚 ，东临太平洋，南到南海诸岛。 5、郑和的船队最远到达哪里？非洲东海岸和红海沿岸 6、统一蒙古草原的是铁木真（成吉思汗） 7、中国十七世纪工业百科全书是：《天工开物》 作者是：宋应星（明） 8、北宋哪里最繁华？开封大相国寺 9、明朝戏剧家和代表作？汤显祖《牡丹亭》 10、《农政全书》、农业、徐光启（明） 11、清朝对新疆地区的管辖措施有？康熙：平定准噶尔叛乱；乾隆：平定大小和卓、设置伊犁将军、哨所、安置土尔扈特部；左宗棠收复新疆，1884年新疆设省。",-1)])])}const h=a(s,[["render",c]]);export{_ as __pageData,h as default};
